const raw = $json;

const headers = raw.payload?.headers || [];

function getHeader(name) {
  const h = headers.find(
    x => (x.name || '').toLowerCase() === name.toLowerCase()
  );
  return h ? h.value || '' : '';
}

const from = getHeader('From');
const subject = getHeader('Subject');
const to = getHeader('To');

const snippet = raw.snippet || '';

function extractPlainText(payload) {
  if (!payload) return '';

  if (payload.mimeType === 'text/plain' && payload.body?.data) {
    return Buffer.from(payload.body.data, 'base64').toString('utf8');
  }

  if (payload.parts && Array.isArray(payload.parts)) {
    for (const part of payload.parts) {
      const found = extractPlainText(part);
      if (found) return found;
    }
  }

  return '';
}

const text = extractPlainText(raw.payload) || snippet;

return {
  json: {
    ...
  raw,
    tenant_id: raw.tenant_id || '',
    account_email: raw.account_email || '',
    gmail_access_token: raw.gmail_access_token || '',
    gmail_refresh_token: raw.gmail_refresh_token || '',
    gmail_expires_at: raw.gmail_expires_at || '',
    from,
    to,
    subject,
    snippet,
    text,
    listId: getHeader('List-Id'),
    threadId: raw.threadId || raw.threadId || ''
  }
};

