const text = ($json.subject + " " + $json.text).toLowerCase();

let intent = "unknown";

if (/beschadigd|kapot|defect|stuk|krassen|scheur|damaged|broken/.test(text)) {
  intent = "damaged";
} else if (/retour|terugsturen|refund|terugbetaling|return/.test(text)) {
  intent = "return";
} else if (/ontbreekt|missen|niet compleet|mist|ontbrekend|missing/.test(text)) {
  intent = "missing_items";
} else if (/waar blijft|niet ontvangen|nog niet|te laat|vertraging|late|delay/.test(text)) {
  intent = "late_delivery";
}

return {
  json: {
    ...$json,
    intent
  }
};

