/**
 * Support Email Gatekeeper (n8n Code node)
 *
 * Place this right after "Parse Email".
 * Returns:
 *  - allowed: true  -> continue workflow
 *  - allowed: false -> stop / route to ignored branch
 */

const input = $json;

// ---------------------------
// Helpers
// ---------------------------
function toStr(v) {
  if (v === null || v === undefined) return "";
  if (typeof v === "string") return v;
  try {
    return String(v);
  } catch {
    return "";
  }
}

function norm(s) {
  return toStr(s).toLowerCase().trim();
}

// Extract email address from "Name <email@x.com>" or raw string
function extractEmail(raw) {
  const s = toStr(raw).trim();
  if (!s) return "";
  const m = s.match(/<([^>]+)>/);
  if (m && m[1]) return m[1].trim().toLowerCase();
  return s.toLowerCase();
}

function includesAny(haystack, needles) {
  const h = norm(haystack);
  return needles.some((n) => h.includes(n));
}

function matchesAnyRegex(text, regexList) {
  const t = toStr(text);
  return regexList.some((r) => r.test(t));
}

function firstNonEmpty(...vals) {
  for (const v of vals) {
    const s = toStr(v).trim();
    if (s) return s;
  }
  return "";
}

// ---------------------------
// Gather fields from Parse Email output
// (Parse Email sometimes outputs both "From" and "from", etc.)
// ---------------------------
const subjectRaw = firstNonEmpty(input.subject, input.Subject);
const snippetRaw = firstNonEmpty(input.snippet, input.Snippet);
const textRaw = firstNonEmpty(input.text, input.Text, input.body, input.Body);

// From: try multiple common keys
const fromRaw = firstNonEmpty(input.from, input.From, input.sender, input.email);
const fromEmail = extractEmail(fromRaw);

// To / delivered-to / listId can help
const toRaw = firstNonEmpty(input.to, input.To, input.deliveredTo, input["Delivered-To"]);
const listIdRaw = firstNonEmpty(input.listId, input["List-Id"], input["list-id"], input["List-id"]);

// If your parser returns headers object, also consider it
const headers = input.headers || input.payload?.headers || null;

// Pull some header-like strings for matching (optional)
const headerBlob = headers ? JSON.stringify(headers) : "";

// Make one big text to classify
const subject = toStr(subjectRaw).trim();
const snippet = toStr(snippetRaw).trim();
const text = toStr(textRaw).trim();
const fullText = `${subject}\n\n${snippet}\n\n${text}\n\n${toStr(toRaw)}\n\n${toStr(listIdRaw)}`.toLowerCase();

// ---------------------------
// Hard block rules (senders / patterns)
// ---------------------------

// Senders/domains that are almost never "customer support requests"
const BLOCK_FROM_CONTAINS = [
  "no-reply",
  "noreply",
  "donotreply",
  "do-not-reply",
  "mailer-daemon",
  "postmaster",
  "bounce",
  "notifications@",
  "notification@",
  "news@",
  "newsletter@",
  "support@webshare.io",              // jouw voorbeeld
  "followsuggestions@mail.instagram.com", // jouw voorbeeld
  "mail.instagram.com",
  "facebookmail.com",
  "accounts.google.com",
];

// Domain-level blocks (receipts, social, automated)
const BLOCK_FROM_DOMAIN_ENDS = [
  "@mail.instagram.com",
  "@facebookmail.com",
  "@accounts.google.com",
  "@noreply.google.com",
  "@google.com", // let op: dit blokt ook echte google users; daarom alleen gebruiken als jij dit echt wil
];

// Subject keywords that are almost always automated/irrelevant
const BLOCK_SUBJECT_CONTAINS = [
  "receipt",
  "invoice",
  "payment",
  "paid",
  "order confirmation",
  "bevestiging",
  "bevestigingsmail",
  "factuur",
  "betaal",
  "betaling",
  "abonnee",
  "subscription",
  "trial",
  "your webshare software receipt", // jouw voorbeeld
  "security alert",
  "login alert",
  "new login",
  "verification",
  "verify your email",
  "confirm your email",
  "password reset",
  "reset your password",
  "two-factor",
  "2fa",
  "otp",
  "code:",
  "welcome to",
  "thanks for signing up",
];

// Newsletter / marketing indicators
const BLOCK_MARKETING_CONTAINS = [
  "unsubscribe",
  "afmelden",
  "view in browser",
  "bekijk in browser",
  "marketing",
  "promotion",
  "promotie",
  "advertisement",
];

// Regex patterns that scream “automated”
const BLOCK_REGEX = [
  /unsubscribe/i,
  /afmelden/i,
  /do-?not-?reply/i,
  /no-?reply/i,
  /mailer-daemon/i,
  /password\s*reset/i,
  /verify\s*your\s*email/i,
  /\bsecurity\s*alert\b/i,
  /\blogin\s*alert\b/i,
];

// ---------------------------
// Positive "support intent" rules
// If none match, we can still allow, but we prefer to block obvious non-support.
// ---------------------------
const SUPPORT_KEYWORDS = [
  "bestelling",
  "order",
  "ordernummer",
  "pakket",
  "levering",
  "bezorg",
  "track",
  "trace",
  "t&t",
  "retour",
  "refund",
  "terug",
  "kapot",
  "beschadigd",
  "defect",
  "ontbreekt",
  "missen",
  "garantie",
  "klacht",
  "probleem",
  "vraag",
  "help",
];

// Detect if this looks like human-written (rough heuristic)
function looksHuman(text) {
  const t = norm(text);
  if (!t) return false;

  // If it contains typical email sign-offs or natural phrasing
  const humanMarkers = ["groetjes", "met vriendelijke groet", "alvast bedankt", "hoi", "hallo", "beste", "kunt u", "kunnen jullie"];
  if (humanMarkers.some((m) => t.includes(m))) return true;

  // If it contains question marks
  if (t.includes("?")) return true;

  return false;
}

// ---------------------------
// Decision engine
// ---------------------------

let allowed = true;
let reason = "OK";

// 1) Hard block: list emails (newsletter)
if (toStr(listIdRaw).trim()) {
  allowed = false;
  reason = "Has List-Id header (newsletter/list mail)";
}

// 2) Hard block: from contains blocked patterns
if (allowed && includesAny(fromEmail, BLOCK_FROM_CONTAINS)) {
  allowed = false;
  reason = `Blocked sender pattern: ${fromEmail}`;
}

// 3) Hard block: from domain ends
if (allowed && BLOCK_FROM_DOMAIN_ENDS.some((d) => fromEmail.endsWith(d))) {
  allowed = false;
  reason = `Blocked sender domain: ${fromEmail}`;
}

// 4) Hard block: subject contains automated keywords
if (allowed && includesAny(subject, BLOCK_SUBJECT_CONTAINS)) {
  allowed = false;
  reason = `Blocked subject keyword: "${subject}"`;
}

// 5) Hard block: marketing content markers
if (allowed && includesAny(fullText, BLOCK_MARKETING_CONTAINS)) {
  allowed = false;
  reason = "Looks like newsletter/marketing (unsubscribe markers)";
}

// 6) Hard block: regex automated
if (allowed && matchesAnyRegex(fullText, BLOCK_REGEX)) {
  allowed = false;
  reason = "Matches automated email regex rule";
}

// 7) Soft allow: if it clearly looks like support
const supportHit = SUPPORT_KEYWORDS.some((k) => fullText.includes(k));
const humanHit = looksHuman(fullText);

// 8) If it doesn't look like support AND doesn't look human, block it
// This prevents random system notifications slipping through even if they didn't match keywords above.
if (allowed && !supportHit && !humanHit) {
  allowed = false;
  reason = "No support keywords and does not look like human-written support email";
}

// ---------------------------
// Return normalized payload
// We keep original fields, but add allowed + reason + normalized fields.
// ---------------------------
return {
  json: {
    ...input,
    normalized: {
      subject,
      snippet,
      text,
      fromEmail,
      to: toStr(toRaw).trim(),
      listId: toStr(listIdRaw).trim(),
    },
    allowed,
    blockedReason: allowed ? null : reason,
  }
};

const tenants = $('Refresh Token If Expired').all();
const gmailResponses = $input.all();
const result = [];

for (let i = 0; i < gmailResponses.length; i++) {
  const tenant = tenants[i].json;
  const msgs = gmailResponses[i].json.messages || [];

  for (const m of msgs) {
    result.push({
      json: {
        tenant_id: tenant.tenant_id,
        account_email: tenant.account_email,
        gmail_access_token: tenant.access_token,
        gmail_refresh_token: tenant.refresh_token,
        gmail_expires_at: tenant.expires_at,
        message_id: m.id,
        threadId: m.threadId
      }
    });
  }
}

return result;

const input = $json;

const to = input.from;
const subject = input.draft?.subject || input.subject;
const body = input.draft?.body || '';
const threadId = input.threadId || '';
const messageId = input.message_id || '';

const email = [
  `To: ${to}`,
  `Subject: ${subject}`,
  `In-Reply-To: ${messageId}`,
  `References: ${messageId}`,
  `Content-Type: text/plain; charset=utf-8`,
  `MIME-Version: 1.0`,
  ``,
  body
].join('\r\n');

const raw = Buffer.from(email)
  .toString('base64')
  .replace(/\+/g, '-')
  .replace(/\//g, '_')
  .replace(/=+$/, '');

return {
  json: {
    ...input,
    raw,
    threadId
  }
};

const item = $json;
const expiresAt = new Date(item.expires_at).getTime();
const now = Date.now();
const isExpired = now >= expiresAt - 60000; // 1 minuut buffer

return {
  json: {
    ...item,
    needs_refresh: isExpired
  }
};
